const n=JSON.parse(`{"key":"v-fb4b8bec","path":"/learningNote/JSNote/defineproperty%E6%96%B9%E6%B3%95.html","title":"Object.defineproperty 方法","lang":"zh-CN","frontmatter":{"title":"Object.defineproperty 方法","category":["JavaScript","Web"],"tag":["JavaScript","advanced"]},"headers":[{"level":2,"title":"简述","slug":"简述","link":"#简述","children":[]},{"level":2,"title":"简单样例","slug":"简单样例","link":"#简单样例","children":[]}],"git":{"createdTime":1693366612000,"updatedTime":1693366612000,"contributors":[{"name":"Jeacson_Snake","email":"Jeacson_Snake@outlook.com","commits":1}]},"readingTime":{"minutes":0.84,"words":252},"filePathRelative":"learningNote/JSNote/defineproperty方法.md","localizedDate":"2023年8月30日","excerpt":"<h2> 简述</h2>\\n<p>Object.defineProperty 是 JavaScript 中 Object 类下的一个高级函数, 它可以用其内置的 <em>getter</em> 与 <em>setter</em> 对传入的数据进行修改操作。一般用于旧时各种JS框架作响应式数据用。由于该方法本质较为臃肿且已经有相应方法做替代，现在大部分框架已经采用 ES6 中的 Proxy/Reflect 新方法作为优先选择。</p>\\n<h2> 简单样例</h2>\\n<div class=\\"language-javascript line-numbers-mode\\" data-ext=\\"js\\"><pre class=\\"language-javascript\\"><code>        <span class=\\"token keyword\\">let</span> number <span class=\\"token operator\\">=</span> <span class=\\"token number\\">18</span><span class=\\"token punctuation\\">;</span>\\n        <span class=\\"token keyword\\">let</span> person <span class=\\"token operator\\">=</span> <span class=\\"token punctuation\\">{</span>\\n            <span class=\\"token literal-property property\\">name</span><span class=\\"token operator\\">:</span> <span class=\\"token string\\">'Jeasfds'</span><span class=\\"token punctuation\\">,</span>\\n            <span class=\\"token literal-property property\\">sex</span><span class=\\"token operator\\">:</span> <span class=\\"token string\\">' male'</span>\\n        <span class=\\"token punctuation\\">}</span>\\n\\n        Object<span class=\\"token punctuation\\">.</span><span class=\\"token function\\">defineProperty</span><span class=\\"token punctuation\\">(</span>person<span class=\\"token punctuation\\">,</span> <span class=\\"token string\\">'ages'</span><span class=\\"token punctuation\\">,</span> <span class=\\"token punctuation\\">{</span>\\n            <span class=\\"token comment\\">// value: 18,</span>\\n            <span class=\\"token literal-property property\\">enumerable</span><span class=\\"token operator\\">:</span> <span class=\\"token boolean\\">true</span><span class=\\"token punctuation\\">,</span><span class=\\"token comment\\">//控制属性是否可以枚举（默认为false）</span>\\n            <span class=\\"token literal-property property\\">writable</span><span class=\\"token operator\\">:</span><span class=\\"token boolean\\">true</span><span class=\\"token punctuation\\">,</span><span class=\\"token comment\\">//控制属性是否可以被修改（默认为false）</span>\\n            <span class=\\"token literal-property property\\">configurable</span><span class=\\"token operator\\">:</span><span class=\\"token boolean\\">true</span><span class=\\"token punctuation\\">,</span><span class=\\"token comment\\">//控制属性是否可以被删除（默认为false）</span>\\n\\n\\n            <span class=\\"token comment\\">//当有人读取 'person' 的 'age' 属性值时，get 函数（getter）会被调用， 且返回值为age值</span>\\n            <span class=\\"token function\\">get</span><span class=\\"token punctuation\\">(</span><span class=\\"token punctuation\\">)</span> <span class=\\"token punctuation\\">{</span>\\n                <span class=\\"token keyword\\">return</span> number<span class=\\"token punctuation\\">;</span>\\n            <span class=\\"token punctuation\\">}</span><span class=\\"token punctuation\\">,</span>\\n            <span class=\\"token comment\\">//当有人修改 'person' 的 'age' 属性值时，set 函数（setter）会被调用， 且会收到修改的具体值</span>\\n            <span class=\\"token function\\">set</span><span class=\\"token punctuation\\">(</span>value<span class=\\"token punctuation\\">)</span> <span class=\\"token punctuation\\">{</span>\\n                number <span class=\\"token operator\\">=</span> value<span class=\\"token punctuation\\">;</span>\\n            <span class=\\"token punctuation\\">}</span>\\n        <span class=\\"token punctuation\\">}</span><span class=\\"token punctuation\\">)</span>\\n\\n</code></pre><div class=\\"line-numbers\\" aria-hidden=\\"true\\"><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div></div></div>"}`);export{n as data};
